"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

type StepperProps = {
  defaultStep?: number
  step?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
  linear?: boolean
}

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepChange: (step: number) => void
  linear: boolean
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  defaultStep = 0,
  step: controlledStep,
  onStepChange,
  orientation = "horizontal",
  linear = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)
  const activeStep = controlledStep ?? uncontrolledStep

  const handleStepChange = React.useCallback(
    (newStep: number) => {
      if (controlledStep === undefined) {
        setUncontrolledStep(newStep)
      }
      onStepChange?.(newStep)
    },
    [controlledStep, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{
        activeStep,
        orientation,
        onStepChange: handleStepChange,
        linear,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        role="group"
        aria-label="progress"
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep, orientation } = useStepper()

  const isActive = activeStep === step
  const isCompleted = activeStep > step
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider
      value={{
        step,
        isActive,
        isCompleted,
        isDisabled: disabled,
      }}
    >
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "cn-stepper-item group/stepper-item",
          orientation === "horizontal"
            ? "flex flex-1 items-center gap-2"
            : "flex flex-col gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange, linear, activeStep } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepperItem()

  const isClickable = !isDisabled && (!linear || isCompleted || step <= activeStep + 1)

  return (
    <button
      data-slot="stepper-trigger"
      aria-current={isActive ? "step" : undefined}
      disabled={!isClickable}
      onClick={() => {
        if (isClickable) {
          onStepChange(step)
        }
      }}
      className={cn(
        "cn-stepper-trigger inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:pointer-events-none disabled:opacity-50",
        isActive && "border-primary bg-primary text-primary-foreground",
        isCompleted && "border-primary bg-primary text-primary-foreground",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/25 bg-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (isCompleted ? (
          <IconPlaceholder
            lucide="CheckIcon"
            tabler="IconCheck"
            hugeicons="CheckmarkIcon"
            phosphor="CheckIcon"
            remixicon="RiCheckLine"
            className="size-4"
          />
        ) : (
          step + 1
        ))}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"div">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title cn-font-heading text-sm font-medium",
        isActive || isCompleted
          ? "text-foreground"
          : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      className={cn(
        "cn-stepper-separator transition-colors",
        orientation === "horizontal"
          ? "h-0.5 flex-1"
          : "ml-4 w-0.5 min-h-4 self-stretch",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (activeStep !== step) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

