  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)
  const activeStep = controlledStep ?? uncontrolledStep

  const handleStepChange = React.useCallback(
    (newStep: number) => {
      if (controlledStep === undefined) {
        setUncontrolledStep(newStep)
      }
      onStepChange?.(newStep)
    },
    [controlledStep, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{
        activeStep,
        orientation,
        onStepChange: handleStepChange,
        linear,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        role="group"
        aria-label="progress"
        className={cn(
          "group/stepper flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep, orientation } = useStepper()

  const isActive = activeStep === step
  const isCompleted = activeStep > step
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider
      value={{
        step,
        isActive,
        isCompleted,
        isDisabled: disabled,
      }}
    >
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "group/stepper-item",
          orientation === "horizontal"
            ? "flex flex-1 items-center gap-2"
            : "flex flex-col gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange, linear, activeStep } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepperItem()

  const isClickable =
    !isDisabled && (!linear || isCompleted || step <= activeStep + 1)

  return (
    <button
      data-slot="stepper-trigger"
      aria-current={isActive ? "step" : undefined}
      disabled={!isClickable}
      onClick={() => {
        if (isClickable) {
          onStepChange(step)
        }
      }}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:pointer-events-none disabled:opacity-50",
        isActive && "border-primary bg-primary text-primary-foreground",
        isCompleted && "border-primary bg-primary text-primary-foreground",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/25 bg-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (isCompleted ? <CheckIcon className="size-4" /> : step + 1)}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"div">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      className={cn(
        "transition-colors",
        orientation === "horizontal"
          ? "h-0.5 flex-1"
          : "ml-4 min-h-4 w-0.5 self-stretch",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (activeStep !== step) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

